+
+.gateway-code {
+  margin-top: 14px !important;
+}
+
+.gateway-envelope {
+  margin-top: 10px !important;
+  color: #475569 !important;
+  font-size: 12px !important;
+  line-height: 17px !important;
+}
+
+.setting-row {
+  margin-top: 18px;
+  display: grid;
+  grid-template-columns: 1fr auto;
+  gap: 16px;
+  align-items: center;
+  padding: 16px;
+}
+
+.compact-field {
+  width: 220px;
+}
+
+.setting-row strong {
+  display: block;
+  color: #0f172a;
+  font-size: 14px;
+}
+
+.setting-row span {
+  display: block;
+  margin-top: 3px;
+  color: #64748b;
+  font-size: 12px;
+}
+
+.code-block {
+  margin-top: 18px;
+  border: 1px solid #e2e8f0;
+  border-radius: 10px;
+  background: #0f172a;
+  color: #e2e8f0;
+  padding: 16px;
+  overflow: auto;
+  font-size: 13px;
+  line-height: 19px;
+}
+
+.data-table {
+  width: 100%;
+  margin-top: 18px;
+  border: 1px solid #e2e8f0;
+  border-collapse: separate;
+  border-spacing: 0;
+  border-radius: 12px;
+  overflow: hidden;
+  background: #ffffff;
+  font-size: 13px;
+}
+
+.data-table th,
+.data-table td {
+  border-bottom: 1px solid #eef2f7;
+  padding: 11px 12px;
+  text-align: left;
+  vertical-align: top;
+}
+
+.data-table th {
+  background: #f8fafc;
+  color: #475569;
+  font-size: 12px;
+  font-weight: 720;
+}
+
+.debug-list {
+  margin-top: 18px;
+  display: flex;
+  flex-direction: column;
+  gap: 10px;
+}
+
+.debug-item {
+  border: 1px solid #e2e8f0;
+  border-radius: 10px;
+  background: #ffffff;
+  padding: 12px;
+}
+
+.debug-item summary {
+  cursor: pointer;
+  color: #0f172a;
+  font-size: 13px;
+  font-weight: 650;
+}
+
+.debug-item pre {
+  overflow: auto;
+  color: #334155;
+  font-size: 12px;
+  line-height: 18px;
+}
+
+@media (max-width: 900px) {
+  .settings-shell {
+    grid-template-columns: 1fr;
+  }
+
+  .settings-sidebar {
+    min-height: auto;
+    position: static;
+  }
+
+  .settings-nav {
+    display: grid;
+    grid-template-columns: repeat(2, minmax(0, 1fr));
+  }
+
+  .settings-main {
+    padding: 22px;
+  }
+
+  .section-heading,
+  .provider-header,
+  .provider-grid,
+  .gateway-toggle-card,
+  .default-panel {
+    grid-template-columns: 1fr;
+  }
+
+  .gateway-switch {
+    justify-self: start;
+  }
+}
